  ('real-estate-moex-01557', 'real-estate', 'real-estate-moex-104-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依區域計畫法之規定，區域計畫公告實施後，有關直轄市或縣（市）政府應製定非都市土地使用分區圖， 並編定各種使用地，於報經上級主管機關核備後實施管制，請指出該使用分區圖及使用地之製定與編定 的依據為何？', '["非都市土地之開發計畫", "非都市土地分區使用計畫", "非都市土地產業發展計畫", "非都市土地管制計畫"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6ad9e9774ff9", "answer_pdf_sha1": "5c8489f89016", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
